/* can_bus.h - CAN Bus Driver Interface */
#ifndef CAN_BUS_H
#define CAN_BUS_H

#include <stdint.h>
#include <stdbool.h>

#define CAN_MAX_DATA_LEN     8U
#define CAN_STD_ID_MASK      0x7FFU
#define CAN_EXT_ID_MASK      0x1FFFFFFFU

typedef struct {
    uint32_t id;
    uint8_t  data[CAN_MAX_DATA_LEN];
    uint8_t  dlc;
    bool     is_extended_id;
    bool     is_remote_frame;
    uint8_t  bus_id;        /* NEW: multi-bus support - breaks aggregate init */
    uint32_t timestamp_us;  /* NEW: hardware timestamp - breaks aggregate init */
} can_frame_t;

typedef void (*can_rx_cb_t)(const can_frame_t *frame);

/* BREAKING: can_init now takes bus_id as first param for multi-bus support */
int  can_init(uint8_t bus_id, uint32_t baudrate, can_rx_cb_t rx_callback);
int  can_send(const can_frame_t *frame);
void can_set_filter(uint32_t filter_id, uint32_t filter_mask);
bool can_bus_off_detected(void);
void can_deinit(void);

#endif /* CAN_BUS_H */

